import React, { Component } from "react";

class Experience extends Component {
  experiencesList = [
    {
      title: "Full Stack Developer",
      startDate: "August 2019",
      endDate: "current",
      companyName: "August 99 Inc. - Canstar Division",
      companyUrl: "https://www.august99.com",
      desc: [
        "Develop fronted website architecture and design user interactions on web pages",
        "Develop fronted website architecture and design user interactions on web pages",
        "Develop fronted website architecture and design user interactions on web pages",
        "Develop fronted website architecture and design user interactions on web pages",
      ],
    },
    {
      title: "Full Stack Developer",
      startDate: "August 2019",
      endDate: "current",
      companyName: "August 99 Inc. - Canstar Division",
      companyUrl: "https://www.august99.com",
    },
    {
      title: "32323",
      startDate: "August 2019",
      endDate: "current",
      companyName: "August 99 Inc. - Canstar Division",
      companyUrl: "https://www.august99.com",
    },
    {
      title: "kkkk",
      startDate: "August 2019",
      endDate: "current",
      companyName: "August 99 Inc. - Canstar Division",
      companyUrl: "https://www.august99.com",
    },
  ];
  render() {
    return (
      <React.Fragment>
        <div className="about-container">
          <div className="row">
            <div className="col-md-12">
              <h2>Experience</h2>
            </div>
          </div>
          <div className="row experience">
            {this.experiencesList.map((exp) => (
              <div className="col-md-3">
                <h4>
                  {exp.title}
                  <p>
                    {exp.startDate} - {exp.endDate}
                  </p>
                  <p>
                    <a href={exp.companyUrl}>{exp.companyName}</a>
                  </p>
                </h4>
                <ul>{exp.desc.map((x) => ({ x }))}</ul>
              </div>
            ))}
          </div>
        </div>
      </React.Fragment>
    );
  }
}

export default Experience;
